import{o as a,f as s,y as t}from"./framework.2171159c.js";const r='{"title":"Махавакья","description":"","frontmatter":{"title":"Махавакья","subtitle":"<p class=\\"sanskrt\\">महावाक्य</p>\\r\\n<p class=\\"transcript\\">Mahāvākya</p>\\r\\nВеликие изречения упанишад","tags":"mantra"},"relativePath":"mantra/mahavakya/index.md","lastUpdated":1624804080206}',i={},n=t('<p>[sect] [sans]प्रज्ञानम् ब्रह्म[/sans] [trans]prajñānam brahma[/trans] Чистое сознание <em>(prajñānam)</em> есть Абсолютная реальность <em>(brahma)</em>. [small]— «Айтарея-упанишада» 3.3 «Ригведы»[/small] [/sect]</p><p>[sect] [sans]अहं ब्रह्मास्मि[/sans] [trans]ahaṃ brahmāsmi[/trans] Я <i>(ahaṃ)</i> есть <i>(аsmi)</i> Абсолютная реальность <i>(brahma)</i>. [small]— «Брихадараньяка-упанишада» 1.4.10 «Яджурведы»)[/small] [/sect]</p><h2 class="sanskrt">तत् त्वम् असि / तत्त्वमसि</h2><p class="transcript">tat tvam asi</p><p class="translation">То <i>(tat)</i> ты <i>(tvam)</i> еси <i>(asi)</i>.</p> («Чхандогья-упанишада» 6.8.7 «Самаведы») <hr><h2 class="sanskrt">अयम् आत्मा ब्रह्म</h2><p class="transcript">ayam ātmā brahma</p><p class="translation">Эта <i>(ayam)</i> душа <i>(ātmā)</i> есть Абсолютная реальность <i>(brahma)</i>.</p> («Мандукья-упанишад» 1.2 «Атхарваведы») ',11);i.render=function(t,r,i,m,l,p){return a(),s("div",null,[n])};export default i;export{r as __pageData};
